import{_ as e,o as i,c as t,ag as l}from"./chunks/framework.BuUvxvtQ.js";const c=JSON.parse('{"title":"API Guide","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"api-examples.md","filePath":"api-examples.md"}'),r={name:"api-examples.md"};function o(n,a,s,p,d,u){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="api-guide" tabindex="-1">API Guide <a class="header-anchor" href="#api-guide" aria-label="Permalink to &quot;API Guide&quot;">​</a></h1><p>This page summarizes the currently available API surface in the Sky Style web app.</p><h2 id="base-path" tabindex="-1">Base Path <a class="header-anchor" href="#base-path" aria-label="Permalink to &quot;Base Path&quot;">​</a></h2><p>Current API endpoints are served from the web app under:</p><ul><li>/api/*</li></ul><p>Future plan:</p><ul><li>Dedicated API host at api.skystyle.app</li></ul><h2 id="common-endpoints" tabindex="-1">Common Endpoints <a class="header-anchor" href="#common-endpoints" aria-label="Permalink to &quot;Common Endpoints&quot;">​</a></h2><h3 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h3><ul><li>POST /api/style</li><li>Generates outfit recommendations based on weather and profile context</li></ul><h3 id="weather" tabindex="-1">Weather <a class="header-anchor" href="#weather" aria-label="Permalink to &quot;Weather&quot;">​</a></h3><ul><li>POST /api/weather</li><li>POST /api/geocode</li><li>POST /api/demo/weather</li><li>POST /api/demo/geocode</li></ul><h3 id="user-data" tabindex="-1">User Data <a class="header-anchor" href="#user-data" aria-label="Permalink to &quot;User Data&quot;">​</a></h3><ul><li>POST /api/closet</li><li>GET or POST /api/settings</li><li>GET /api/credits</li><li>GET /api/daily-limits</li></ul><h3 id="follow-up-and-chat" tabindex="-1">Follow-up and Chat <a class="header-anchor" href="#follow-up-and-chat" aria-label="Permalink to &quot;Follow-up and Chat&quot;">​</a></h3><ul><li>POST /api/followup</li></ul><h3 id="security-and-privacy" tabindex="-1">Security and Privacy <a class="header-anchor" href="#security-and-privacy" aria-label="Permalink to &quot;Security and Privacy&quot;">​</a></h3><ul><li>POST /api/mfa/setup</li><li>POST /api/mfa/verify</li><li>POST /api/mfa/disable</li><li>GET /api/passkeys/list</li><li>POST /api/passkeys/register</li><li>GET /api/security/logs</li><li>POST /api/privacy/export</li><li>POST /api/privacy/request-deletion</li><li>POST /api/privacy/cancel-deletion</li></ul><h2 id="auth" tabindex="-1">Auth <a class="header-anchor" href="#auth" aria-label="Permalink to &quot;Auth&quot;">​</a></h2><p>Sky Style uses NextAuth v5 with JWT sessions. Client-side session reads are available via:</p><ul><li>/api/auth/session</li></ul><p>Auth route handler:</p><ul><li>/api/auth/[...nextauth]</li></ul><h2 id="integration-notes" tabindex="-1">Integration Notes <a class="header-anchor" href="#integration-notes" aria-label="Permalink to &quot;Integration Notes&quot;">​</a></h2><ul><li>Expect JSON request and response payloads for API endpoints.</li><li>Treat endpoints as product-internal APIs until the standalone API project is launched.</li><li>Apply rate-limit and plan-tier checks in any client integration flow.</li></ul>',25)])])}const m=e(r,[["render",o]]);export{c as __pageData,m as default};
